<script setup>
import { reactive, ref } from 'vue'
import { Head, Link, router } from '@inertiajs/vue3'
import { useI18n } from 'vue-i18n'
import AppLayout from '@/Layouts/AppLayout.vue'

const { t } = useI18n()
const props = defineProps({ documents: { type: Object, required: true }, filters: { type: Object, default: () => ({}) }, serviceCategories: { type: Array, default: () => [] } })
const filters = reactive({ search: props.filters.search ?? '', provider: props.filters.provider ?? '', service_category: props.filters.service_category ?? '', status: props.filters.status ?? '', type: props.filters.type ?? '' })
const comments = ref({})
const types = ['identity', 'diploma', 'certification', 'address_proof', 'other']
const applyFilters = () => router.get('/admin/documents', filters, { preserveState: true, replace: true })
const resetFilters = () => { Object.assign(filters, { search: '', provider: '', service_category: '', status: '', type: '' }); applyFilters() }
const name = user => `${user.first_name} ${user.last_name}`.trim()
const formatSize = bytes => bytes ? `${(bytes / 1024 / 1024).toFixed(1)} Mo` : '—'
function review(document, status) {
    router.patch(`/admin/documents/${document.id}/review`, { status, review_comment: comments.value[document.id] ?? '' }, { preserveScroll: true })
}
function remove(document) {
    if (window.confirm(t('adminDocuments.deleteConfirm'))) router.delete(`/admin/documents/${document.id}`, { preserveScroll: true })
}
</script>

<template><Head :title="$t('adminDocuments.title')"/><AppLayout><main class="admin-documents"><header><div><span>{{ $t('adminDocuments.eyebrow') }}</span><h1>{{ $t('adminDocuments.title') }}</h1><p>{{ $t('adminDocuments.subtitle') }}</p></div></header><section><form @submit.prevent="applyFilters"><input v-model.trim="filters.provider" type="search" :placeholder="$t('adminDocuments.providerSearch')"><input v-model.trim="filters.search" type="search" :placeholder="$t('adminDocuments.search')"><select v-model="filters.service_category"><option value="">{{ $t('adminDocuments.allServiceCategories') }}</option><option v-for="category in serviceCategories" :key="category.id" :value="category.id">{{ category.name }}</option></select><select v-model="filters.status"><option value="">{{ $t('adminDocuments.allStatuses') }}</option><option v-for="status in ['en_attente','valide','rejete']" :key="status" :value="status">{{ $t(`providerDocuments.statuses.${status}`) }}</option></select><select v-model="filters.type"><option value="">{{ $t('adminDocuments.allTypes') }}</option><option v-for="type in types" :key="type" :value="type">{{ $t(`providerDocuments.types.${type}`) }}</option></select><button>{{ $t('adminDocuments.filter') }}</button><button type="button" class="secondary" @click="resetFilters">{{ $t('adminDocuments.reset') }}</button></form><div v-if="documents.data.length" class="documents-grid"><article v-for="document in documents.data" :key="document.id"><header><div><strong>{{ name(document.user) }}</strong><small>{{ document.user.email }}</small><b :class="['identity-badge', { verified: document.user.identity_verified_at }]">{{ document.user.identity_verified_at ? $t('serviceShow.verifiedProfile') : $t('serviceShow.unverifiedProfile', 'Profil non vérifié') }}</b></div><span :class="`status-${document.status}`">{{ $t(`providerDocuments.statuses.${document.status}`) }}</span></header><h2>{{ document.label || $t(`providerDocuments.types.${document.document_type}`) }}</h2><p>{{ document.original_name }} · {{ formatSize(document.file_size) }}</p><a :href="`/admin/documents/${document.id}/download`">{{ $t('adminDocuments.inspect') }}</a><textarea v-model="comments[document.id]" rows="2" :placeholder="$t('adminDocuments.comment')"></textarea><footer><button type="button" class="reject" @click="remove(document)">{{ $t('adminDocuments.delete') }}</button><button v-if="document.status !== 'en_attente'" type="button" class="approve" @click="review(document,'en_attente')">{{ $t('adminDocuments.reopen') }}</button><button type="button" class="reject" @click="review(document,'rejete')">{{ $t('adminDocuments.reject') }}</button><button type="button" class="approve" @click="review(document,'valide')">{{ $t('adminDocuments.approve') }}</button></footer></article></div><p v-else>{{ $t('adminDocuments.empty') }}</p><nav v-if="documents.links?.length>3"><Link v-for="link in documents.links" :key="link.label" :href="link.url||''" :class="{active:link.active,disabled:!link.url}" v-html="link.label"/></nav></section></main></AppLayout></template>

<style scoped>
.admin-documents{width:min(1180px,calc(100% - 2rem));margin:2.5rem auto 4rem;color:#17251e}.admin-documents>header{padding:2rem;border-radius:22px;background:linear-gradient(125deg,#0c3d27,#177245);color:#fff}.admin-documents>header span{font-size:.75rem;font-weight:800;letter-spacing:.1em;text-transform:uppercase}.admin-documents h1{margin:.4rem 0}.admin-documents>header p{margin:0;color:rgba(255,255,255,.8)}.admin-documents>section{margin-top:1.25rem;padding:1.5rem;border:1px solid #e1e9e4;border-radius:18px;background:#fff}.admin-documents form{display:grid;grid-template-columns:minmax(170px,1fr) minmax(170px,1fr) 190px 150px 170px auto auto;gap:.7rem}.admin-documents form>*{box-sizing:border-box;min-width:0;min-height:42px;padding:.65rem .8rem;border:1px solid #ccd8d1;border-radius:9px;background:#fff}.admin-documents form button{background:#177245;color:#fff;font-weight:800}.admin-documents form .secondary{background:#fff;color:#526158}.documents-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:1rem;margin-top:1.3rem}.documents-grid article{padding:1.2rem;border:1px solid #dfe8e2;border-radius:14px}.documents-grid article>header{display:flex;justify-content:space-between;gap:1rem}.documents-grid header small{display:block;color:#718078}.documents-grid header>span{padding:.3rem .55rem;border-radius:999px;font-size:.72rem;font-weight:800}.status-en_attente{background:#fff3d6;color:#946411}.status-valide{background:#e5f5ec;color:#146c43}.status-rejete{background:#feeceb;color:#b42318}.documents-grid h2{margin:1rem 0 .25rem;font-size:1.05rem}.documents-grid p{color:#718078}.documents-grid>a{display:inline-block;color:#176b45;font-weight:800}.documents-grid textarea{box-sizing:border-box;width:100%;margin-top:1rem;padding:.65rem;border:1px solid #ccd8d1;border-radius:8px}.documents-grid footer{display:flex;justify-content:flex-end;gap:.5rem;margin-top:.6rem}.documents-grid footer button{padding:.6rem .8rem;border:0;border-radius:8px;color:#fff;font-weight:800;cursor:pointer}.reject{background:#bd3047}.approve{background:#177245}.admin-documents nav{display:flex;justify-content:center;gap:.35rem;margin-top:1rem}.admin-documents nav a{padding:.45rem .65rem;border-radius:7px;color:#176b45;text-decoration:none}.admin-documents nav a.active{background:#176b45;color:#fff}.admin-documents nav a.disabled{pointer-events:none;opacity:.4}@media(max-width:1050px){.admin-documents form{grid-template-columns:1fr 1fr}.documents-grid{grid-template-columns:1fr}}@media(max-width:520px){.admin-documents form{grid-template-columns:1fr}}
</style>

<style scoped>
.identity-badge{display:inline-flex;margin-top:.4rem;padding:.25rem .5rem;border-radius:999px;background:#fff3d6;color:#946411;font-size:.7rem}.identity-badge.verified{background:#e5f5ec;color:#146c43}
</style>
